from flask import Flask
from flask_graphql import GraphQLView
import graphene


PRODUCTS = [
    {"id": "1", "name": "Wireless Mouse", "description": "Ergonomic wireless mouse", "price": 29.99, "category_id": "1"},
    {"id": "2", "name": "Mechanical Keyboard", "description": "RGB mechanical keyboard", "price": 89.99, "category_id": "1"},
    {"id": "3", "name": "Noise Cancelling Headphones", "description": "Over-ear noise cancelling headphones", "price": 199.99, "category_id": "2"},
]

CATEGORIES = [
    {"id": "1", "name": "Computer Accessories"},
    {"id": "2", "name": "Audio"},
]

REVIEWS = [
    {"id": "1", "product_id": "1", "user_name": "Alice", "rating": 5, "comment": "Excellent mouse!"},
    {"id": "2", "product_id": "1", "user_name": "Bob", "rating": 4, "comment": "Works well and feels comfortable."},
    {"id": "3", "product_id": "2", "user_name": "Charlie", "rating": 5, "comment": "Great typing experience."},
    {"id": "4", "product_id": "3", "user_name": "Dana", "rating": 4, "comment": "Sound quality is fantastic."},
]


class CategoryType(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    products = graphene.List(lambda: ProductType)

    def resolve_products(parent, info):
        return [p for p in PRODUCTS if p["category_id"] == parent["id"]]


class ReviewType(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user_name = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()


class ProductType(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category = graphene.Field(CategoryType)
    reviews = graphene.List(ReviewType)

    def resolve_category(parent, info):
        return next((c for c in CATEGORIES if c["id"] == parent["category_id"]), None)

    def resolve_reviews(parent, info):
        return [r for r in REVIEWS if r["product_id"] == parent["id"]]


class Query(graphene.ObjectType):
    products = graphene.List(ProductType, category_id=graphene.ID(), name=graphene.String())
    product = graphene.Field(ProductType, id=graphene.ID(required=True))
    categories = graphene.List(CategoryType)
    category = graphene.Field(CategoryType, id=graphene.ID(required=True))
    reviews = graphene.List(ReviewType, product_id=graphene.ID())
    review = graphene.Field(ReviewType, id=graphene.ID(required=True))

    def resolve_products(root, info, category_id=None, name=None):
        results = PRODUCTS
        if category_id is not None:
            results = [p for p in results if p["category_id"] == category_id]
        if name is not None:
            lowered = name.lower()
            results = [p for p in results if lowered in p["name"].lower()]
        return results

    def resolve_product(root, info, id):
        return next((p for p in PRODUCTS if p["id"] == id), None)

    def resolve_categories(root, info):
        return CATEGORIES

    def resolve_category(root, info, id):
        return next((c for c in CATEGORIES if c["id"] == id), None)

    def resolve_reviews(root, info, product_id=None):
        results = REVIEWS
        if product_id is not None:
            results = [r for r in results if r["product_id"] == product_id]
        return results

    def resolve_review(root, info, id):
        return next((r for r in REVIEWS if r["id"] == id), None)


schema = graphene.Schema(query=Query)

app = Flask(__name__)
app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True,
    ),
)

@app.route("/")
def index():
    return {
        "service": "e-commerce-api",
        "graphql_endpoint": "/graphql",
        "graphiql_enabled": True,
    }


if __name__ == "__main__":
    app.run(debug=True)